<script lang="ts">
	import { page } from '$app/state';
	import { i18nConfig, type Lang } from '$i18n';
	import { t } from '$i18n';
	import { onMount } from 'svelte';

	let { lang }: { lang: Lang } = $props();
	let mobileOpen = $state(false);

	// Focus trap: keep focus inside drawer when open
	let drawerRef = $state<HTMLElement>();

	onMount(() => {
		const handleKey = (e: KeyboardEvent) => {
			if (!mobileOpen) return;
			if (e.key === 'Escape') {
				mobileOpen = false;
				return;
			}
			// Focus trap: when drawer is open and focus leaves drawer, bring it back
			if (e.key === 'Tab' && drawerRef) {
				const focusable = drawerRef.querySelectorAll<HTMLElement>(
					'a[href], button:not([disabled]), input, select, textarea, [tabindex]:not([tabindex="-1"])'
				);
				if (focusable.length === 0) return;
				const first = focusable[0];
				const last = focusable[focusable.length - 1];
				if (e.shiftKey) {
					if (document.activeElement === first) {
						e.preventDefault();
						last.focus();
					}
				} else {
					if (document.activeElement === last) {
						e.preventDefault();
						first.focus();
					}
				}
			}
		};
		document.addEventListener('keydown', handleKey);
		return () => document.removeEventListener('keydown', handleKey);
	});


	const navItems = $derived([
		{ href: `/${lang}`, label: t(lang, 'nav.home') },
		{ href: `/${lang}/search`, label: t(lang, 'nav.search') },
		{ href: `/${lang}/help`, label: t(lang, 'nav.help') },
		{ href: `/${lang}/about`, label: t(lang, 'nav.about') }
	]);

	const langItems = i18nConfig.supportedLangs.map((l) => ({
		lang: l,
		label: i18nConfig.langDisplayNames[l],
		href: page.url.pathname.replace(/^\/[^/]+/, `/${l}`)
	}));

	function switchLang(newLang: Lang) {
		const newPath = page.url.pathname.replace(/^\/[^/]+/, `/${newLang}`);
		window.location.href = newPath;
	}

	const isActive = (href: string) => page.url.pathname === href;
</script>

<header class="m3-nav-header">
	<nav class="m3-nav-inner">
		<!-- Site name / Logo -->
		<a href="/{lang}" class="m3-nav-brand">
			{t(lang, 'site.name')}
		</a>

		<!-- Desktop Nav Links -->
		<div class="m3-nav-links">
			{#each navItems as item}
				<a
					href={item.href}
					class="m3-nav-link"
					class:m3-nav-link--active={isActive(item.href)}
				>
					{item.label}
				</a>
			{/each}

			<!-- Language selector: tonal button dropdown -->
			<div class="m3-lang-selector">
				<button class="m3-lang-btn">
					{i18nConfig.langDisplayNames[lang]}
					<svg class="m3-lang-chevron" fill="none" stroke="currentColor" viewBox="0 0 24 24">
						<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7" />
					</svg>
				</button>
				<div class="m3-lang-dropdown">
					{#each langItems as item}
						<button
							onclick={() => switchLang(item.lang)}
							class="m3-lang-option"
						>
							{item.label}
						</button>
					{/each}
				</div>
			</div>
		</div>

		<!-- Mobile hamburger -->
		<button
			class="m3-hamburger"
			onclick={() => mobileOpen = !mobileOpen}
			aria-label="Toggle menu"
		>
			<svg class="m3-hamburger-icon" fill="none" stroke="currentColor" viewBox="0 0 24 24">
				{#if mobileOpen}
					<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12" />
				{:else}
					<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 6h16M4 12h16M4 18h16" />
				{/if}
			</svg>
		</button>
	</nav>

	<!-- Mobile Navigation Drawer (right slide-out) -->
	{#if mobileOpen}
		<button
			class="m3-drawer-overlay"
			onclick={() => mobileOpen = false}
			aria-label="Close menu"
		></button>

		<nav class="m3-drawer" class:open={mobileOpen} bind:this={drawerRef}>
			<!-- Drawer header -->
			<div class="m3-drawer-header">
				<span class="m3-drawer-title">
					{t(lang, 'site.name')}
				</span>
				<button
					class="m3-drawer-close"
					onclick={() => mobileOpen = false}
					aria-label="Close menu"
				>
					<svg class="m3-drawer-close-icon" fill="none" stroke="currentColor" viewBox="0 0 24 24">
						<path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12" />
					</svg>
				</button>
			</div>

			{#each navItems as item}
				<a
					href={item.href}
					class="m3-drawer-item"
					class:m3-drawer-item--active={isActive(item.href)}
					onclick={() => mobileOpen = false}
				>
					{item.label}
				</a>
			{/each}

			<div class="m3-drawer-divider"></div>

			<p class="m3-drawer-lang-label">
				{t(lang, 'lang.' + lang)}
			</p>
			{#each langItems as item}
				<button
					class="m3-drawer-item"
					onclick={() => { switchLang(item.lang); mobileOpen = false; }}
				>
					{item.label}
				</button>
			{/each}
		</nav>
	{/if}
</header>

